\begin{tikzpicture}
\path (0,0) rectangle (0.01,0.01);
\begin{axis}[
  width=10cm, height=6cm,
  xlabel={\small Year}, ylabel={\small CPI YoY (\%)},
  xmin=2017.5, xmax=2024.5, ymin=0, ymax=10,
  xtick={2018,2019,2020,2021,2022,2023,2024},
  grid=major, grid style={gray!20},
  tick label style={font=\scriptsize}, label style={font=\scriptsize},
  axis lines=left, every axis plot/.append style={thick}
]
\addplot[color=teal!70!black, dashed, thick] coordinates {(2017.5,2) (2024.5,2)};
\node[font=\scriptsize, text=teal!70!black, anchor=west] at (axis cs:2023.2,2.4) {2\% Fed target};
\addplot[color=orange!80!black, mark=*, mark size=2pt] coordinates {(2018,2.4) (2019,1.8) (2020,1.2) (2021,4.7) (2022,8.0) (2023,4.1) (2024,3.0)};
\node[font=\scriptsize, orange!80!black, anchor=south] at (axis cs:2022,8.2) {8.0\% peak};
\end{axis}
\end{tikzpicture}

\begin{tikzpicture}
\path[use as bounding box] (-0.8,-0.6) rectangle (11.2,6.4);
\begin{axis}[
  width=11cm, height=6.2cm,
  xlabel={$\to$ Unemployment},
  ylabel={Inflation $\uparrow$},
  xmin=0, xmax=8, ymin=0, ymax=7.5,
  axis lines=left,
  ticks=none,
  xlabel style={at={(1.02,0)}, anchor=west, font=\footnotesize\sffamily, text=black!60},
  ylabel style={at={(0,1.04)}, anchor=south, rotate=-90, font=\footnotesize\sffamily, text=black!60},
  tick style={draw=none},
  axis line style={black!55, line width=0.6pt},
  clip=false,
]
\addplot[line width=1.2pt, color=orange!85, smooth, domain=0.3:8, samples=120] {5/(x+0.5)};
\addplot[only marks, mark=*, mark size=2.5pt, color=black!80]
  coordinates {(0.3, 6.25) (1, 3.33) (2, 2) (4, 1.11) (7, 0.625)};
\node[color=orange!75, font=\footnotesize\itshape\sffamily, anchor=south west]
  at (axis cs:3.6, 2.6) {SR Phillips curve};
\end{axis}
\end{tikzpicture}
